INSERT INTO public.candidate_applications (id, request_id, name, email, phone, cover_letter, applied_at, cv_filename, cv_path, screening_status, screening_score, screening_summary, screening_strengths, screening_gaps, screening_recommendation, screening_prompt_version, shortlisted, interview_status, interview_scheduled_at, interview_format, interview_location, interview_notes, cover_letter_filename, outcome, outcome_recorded_at, offer_extended, offer_amount, offer_date, offer_accepted, offer_declined_reason, interview_rounds, days_to_respond) VALUES ('4572f873-6080-40fb-8b59-2137d489e685', 'f28fee9a-978a-4587-bb7e-159c08376608', 'Arjun Mehta', 'arjun.mehta@email.com', '07721901472', NULL, '2026-05-14 17:27:51.217627+00', 'cv_batch_1.pdf', '/Users/navjeetkaur/Desktop/Capstone/backend/cv_uploads/68695553-cc30-463a-9fc4-1ba12609730e.pdf', 'screened', 10, 'The candidate has experience in AI systems and machine learning, but lacks relevant skills and experience in data analysis, financial modeling, and Excel, which are critical for the Investment Data Analyst role.', '["Experience in AI systems", "Knowledge of machine learning"]', '["No experience in data analysis", "Lacks advanced Excel skills", "No understanding of financial modeling", "No communication skills mentioned", "No relevant experience in finance or investment analysis"]', 'poor_match', 'screen-v1', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.candidate_applications (id, request_id, name, email, phone, cover_letter, applied_at, cv_filename, cv_path, screening_status, screening_score, screening_summary, screening_strengths, screening_gaps, screening_recommendation, screening_prompt_version, shortlisted, interview_status, interview_scheduled_at, interview_format, interview_location, interview_notes, cover_letter_filename, outcome, outcome_recorded_at, offer_extended, offer_amount, offer_date, offer_accepted, offer_declined_reason, interview_rounds, days_to_respond) VALUES ('85123931-dff4-4b25-a58b-6622ee258f47', 'e8ff1e7e-6612-4b74-94c9-1c2b7563301c', 'Navjeet Kaur', 'nkrubygambhir@gmail.com', '07721901472', NULL, '2026-05-15 13:52:15.776359+00', 'Navjeet_Kaur_CV.docx', '/Users/navjeetkaur/Desktop/Capstone/backend/cv_uploads/e8e26d56-b28a-4366-846f-4fa54029ddfc.docx', 'screened', 75, 'The candidate has over 12 years of experience in software engineering with a strong focus on AI and Python development. They possess a solid understanding of software development principles and have experience with various technologies, although their primary focus appears to be on AI systems rather than traditional Python application development.', '["Extensive experience in software engineering (12+ years)", "Proficiency in Python and experience with ML pipelines"]', '["Limited direct experience in designing and maintaining high-performance Python applications outside of AI contexts", "No explicit mention of experience with RESTful APIs or microservices architecture in a traditional sense"]', 'good_match', 'screen-v1', true, 'scheduled', '2026-05-23 13:53:00+00', 'video', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.candidate_applications (id, request_id, name, email, phone, cover_letter, applied_at, cv_filename, cv_path, screening_status, screening_score, screening_summary, screening_strengths, screening_gaps, screening_recommendation, screening_prompt_version, shortlisted, interview_status, interview_scheduled_at, interview_format, interview_location, interview_notes, cover_letter_filename, outcome, outcome_recorded_at, offer_extended, offer_amount, offer_date, offer_accepted, offer_declined_reason, interview_rounds, days_to_respond) VALUES ('9a17be75-cf55-4570-9443-f3aad5e67029', 'f28fee9a-978a-4587-bb7e-159c08376608', 'Navjeet Kaur', 'nkrubygambhir@gmail.com', '07721901472', NULL, '2026-05-14 17:32:00.370039+00', 'Navjeet_Kaur_CV.docx', '/Users/navjeetkaur/Desktop/Capstone/backend/cv_uploads/e63bf899-6364-4b80-afeb-8fbb195059b3.docx', 'screened', 20, 'The candidate has extensive experience in AI engineering and software development but lacks relevant skills and experience in investment data analysis. Their background is heavily focused on advanced AI systems rather than the required data analysis and financial modeling for the role.', '[]', '["No experience in data analysis specific to investment data.", "Lacks proficiency in Excel and financial modeling concepts.", "No demonstrated attention to detail in data handling related to finance.", "Insufficient communication skills relevant to preparing reports and presentations for stakeholders."]', 'poor_match', 'screen-v1', false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);


