INSERT INTO public.chat_messages (id, request_id, role, content, created_at) VALUES ('1763a54a-741f-4d36-ac9b-c9fc9f50a276', 'f28fee9a-978a-4587-bb7e-159c08376608', 'assistant', '**Job Title:** Entry Level Investment Data Analyst  
**Department:** Investment Analysis  
**Location:** London, United Kingdom  
