INSERT INTO public.past_jds (id, title, department, content, embedding, created_at) VALUES ('c05680c0-5a65-4b80-82e2-42589278eb01', 'Data Scientist — Energy Transition AI Impact', 'Data Science', 'Job Title: Data Scientist — Energy Transition AI Impact
Company: Faculty
Location: Manchester, United Kingdom
Employment Type: Full-time

A leading AI consultancy based in London is seeking an entry-level Data Scientist to work on impactful projects related to the low-carbon transition. The role involves designing and deploying data science solutions while collaborating with multidisciplinary teams. Ideal candidates should have a strong foundation in data science, programming experience (preferably in Python), and a curiosity about the energy sector. This position offers a full-time opportunity to make a significant real-world impact. #J-18808-Ljbffr', '[-0.01727295,0.00025725365,0.017456055,-0.008834839,0.015182495,0.011894226,-0.02456665,0.041656494,0.012634277,-0.01524353,0.024841309,-0.028900146,-0.04071045,0.00015234947,0.025939941,0.07244873,-0.029251099,0.032440186,-0.015274048,0.067871094,-0.020767212,-0.02217102,0.03515625,-0.015556335,0.029571533,-0.02784729,-0.0027332306,0.0034427643,0.030639648,0.010093689,0.046051025,-0.024917603,-0.012802124,-0.0019950867,0.013885498,0.030853271,0.0055503845,0.016235352,0.005607605,-0.02607727,-0.01751709,-0.059753418,0.006980896,0.047454834,-0.021743774,-0.021636963,-0.018508911,-0.02456665,0.05859375,0.00015854836,-0.028762817,-0.030151367,-0.009101868,2.348423e-05,-0.033996582,0.0019512177,0.012062073,0.042144775,-0.0021705627,-0.019348145,0.012039185,0.008728027,0.051879883,0.049438477,-0.009757996,-0.016159058,-0.025283813,0.04144287,-0.04537964,0.015167236,0.020004272,0.04055786,0.022201538,-0.007205963,0.0047912598,-0.019302368,-0.029434204,-0.012527466,-0.038726807,0.0087509155,-0.0524292,0.015342712,0.0046043396,-0.043914795,0.011962891,-0.020339966,-0.0073127747,-0.060272217,-0.06573486,0.0052108765,-0.00881958,-0.03765869,-0.052581787,0.018859863,0.021514893,-0.0020122528,0.027191162,0.0011692047,0.0059509277,0.035491943,-0.008598328,-0.009048462,0.07330322,0.06109619,0.018661499,-4.3928623e-05,0.005958557,-0.01272583,0.01625061,-0.0055770874,-0.06542969,0.010917664,0.021072388,-0.016296387,-0.0579834,-0.027893066,-0.012931824,-0.013023376,0.0