INSERT INTO public.past_jds (id, title, department, content, embedding, created_at) VALUES ('6a5e4af4-aca0-46d4-a824-57e121c2724b', 'Entry Level Investment Data analyst', 'Data Analytics', 'Job Title: Entry Level Investment Data analyst
Company: Citylife HR
Location: United Kingdom
Employment Type: Full-time

Company Description
 Citylife HR is a UK-based finance recruitment platform dedicated to connecting talented job seekers and trusted employers in the finance sector. From accounting and banking to fintech and financial analysis, Citylife HR offers a curated collection of opportunities, ensuring relevance and quality. Focused on transparency and efficiency, we provide a user-friendly experience for job seekers while helping employers build high-performing teams. With deep expertise in the UK market, we aim to create a reliable recruitment ecosystem that fosters growth and connects professionals to the right opportunities.


 Role Description
 The Investment Data Analyst will play a key role in supporting data-driven decisions within our organization. This is a full-time, on-site position located in the London area, United Kingdom. Responsibilities include collecting, analyzing, and interpreting investment data, creating data models, and generating actionable insights. The role also involves preparing detailed reports, communicating findings to stakeholders, and working collaboratively with various teams to enhance investment strategies.


 Qualifications
 Strong Analytical Skills and a deep understanding of Data AnalyticsProficiency in Statistics and Data ModelingExcellent Communication skills, both written and verbalProficiency in relevant data analysis tools and software (e.g., Excel, Python, R, SQL)Bachelor''s degree in Finance, Data Science, Statistics, Economics, or a related fieldAbility to work collaboratively in an on-site team environmentStrong attention to detail and problem-solving skillsFamiliarity with financial markets and investment concepts is a plus', '[-0.015197754,0.028442383,0.031082153,0.043762207,0.004558563,0.0027370453,0.0025100708,0.04623413,0.01184082,0.020462036,0.018966675,-0.049224854,-0.011016846,-0.01689148,0.04751587,0.043273926,-0.034332275,-0.011100769,-0.0362854,0.08666992,0.026870728,0.02758789,-0.015930176,0.007396698,0.02809143,0.007534027,-0.010574341,0.020004272,-0.022994995,-0.018341064,0.041809082,-0.025436401,-0.036376953,0.06890869,-0.00012564659,0.007736206,0.035095215,0.01285553,0.040924072,-0.015205383,-0.0016498566,-0.025634766,0.041015625,0.031311035,-0.02268982,-0.008903503,-0.03237915,-0.0056152344,0.039794922,0.0037193298,-0.031341553,-0.0042304993,-0.0028247833,0.029846191,-0.025939941,0.01902771,0.027511597,0.010383606,-0.025817871,-0.015052795,0.058013916,-0.01687622,0.0491333,0.04650879,-0.018356323,-0.042816162,-0.03152466,0.032714844,-0.048461914,0.012863159,0.006843567,-0.009025574,0.0037345886,0.019165039,0.010696411,-0.021331787,-0.049804688,-0.0061950684,-0.04196167,-0.007904053,-0.039642334,-0.0072898865,-0.005142212,-0.018417358,0.027557373,-0.052642822,-0.0060768127,-0.031036377,-0.020462036,0.0065689087,-0.01322937,0.01965332,-0.039642334,0.027633667,0.020477295,-0.0065078735,0.01663208,0.00051784515,-0.051361084,0.020187378,-0.012397766,0.0036792755,0.037750244,0.0046310425,0.007045746,0.014694214,0.01033783,-0.040161133,0.03262329,-0.0032672882,-0.10437012,0.025924683,0.0022678375,0.0077171326,-0.0015230179,-0.020355225,-0.02835083,-0.021026611,-0.0